@namespace sv_8f61233ca2f2415d8928b0a07a7c5124.Components.Chat
@using sv_8f61233ca2f2415d8928b0a07a7c5124.Models
@inject IJSRuntime JS

<section class="message-area">
    <div class="message-area__header">
        <h2># @Channel?.Name</h2>
        @if (!string.IsNullOrWhiteSpace(Channel?.Description))
        {
            <p class="message-area__description">@Channel.Description</p>
        }
    </div>

    <div class="message-area__list" @ref="scrollContainer" @onscroll="HandleScroll">
        @if (isLoadingMore)
        {
            <div class="message-area__loading">Loading older messages…</div>
        }

        @foreach (var msg in Messages)
        {
            <MessageBubble Message="msg"
                           ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                           OnOpenThread="OnOpenThread"
                           OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{Channel?.Name}")" OnSend="OnSendMessage" />
</section>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }

    private ElementReference scrollContainer;
    private bool isLoadingMore;

    private int GetThreadReplyCount(int messageId) =>
        ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-area__list')?.scrollTop ?? 1");
        if (scrollTop < 50 && !isLoadingMore)
        {
            isLoadingMore = true;
            await OnLoadMore.InvokeAsync();
            isLoadingMore = false;
        }
    }
}

