toolArgs.file_text:
/* ===== Chat Page Layout ===== */
.chat-page {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* ===== Channel Sidebar ===== */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #1a1d21;
    color: #ccc;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #333;
}

.channel-sidebar__header {
    padding: 16px;
    border-bottom: 1px solid #333;
}

.channel-sidebar__header h3 {
    margin: 0;
    color: #fff;
    font-size: 1.1rem;
}

.channel-sidebar__list {
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #26292e;
}

.channel-item--active {
    background: #1164a3;
    color: #fff;
}

.channel-item__header {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-item__name {
    font-weight: 600;
    font-size: 0.95rem;
}

.channel-item__badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.75rem;
    font-weight: 700;
    padding: 1px 7px;
    border-radius: 10px;
    min-width: 20px;
    text-align: center;
}

.channel-item__description {
    font-size: 0.8rem;
    color: #999;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item--active .channel-item__description {
    color: rgba(255, 255, 255, 0.7);
}

/* ===== Message Area ===== */
.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #fff;
    min-width: 0;
}

.chat-page__main--with-thread {
    flex: 0 0 55%;
}

.chat-page__main--full {
    flex: 1;
}

.message-area__header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
}

.message-area__header h2 {
    margin: 0;
    font-size: 1.15rem;
    color: #1d1c1d;
}

.message-area__description {
    margin: 2px 0 0;
    font-size: 0.85rem;
    color: #616061;
}

.message-area__list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 20px;
}

.message-area__loading {
    text-align: center;
    padding: 12px;
    color: #888;
    font-size: 0.85rem;
}

/* ===== Message Bubble ===== */
.message-bubble {
    padding: 8px 12px;
    border-radius: 6px;
    margin-bottom: 4px;
    position: relative;
    transition: background 0.1s;
}

.message-bubble:hover {
    background: #f8f8f8;
}

.message-bubble--highlighted {
    background: #fff8e1;
}

.message-bubble__header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-bubble__author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1d1c1d;
}

.message-bubble__time {
    font-size: 0.75rem;
    color: #999;
}

.message-bubble__content {
    font-size: 0.95rem;
    line-height: 1.5;
    color: #1d1c1d;
    word-wrap: break-word;
}

.message-bubble__thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 4px;
}

.message-bubble__thread-link:hover {
    text-decoration: underline;
}

/* Action buttons on hover */
.message-bubble__actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 6px rgba(0,0,0,0.1);
    z-index: 10;
}

.message-bubble__action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    border-radius: 4px;
    color: #555;
    white-space: nowrap;
}

.message-bubble__action-btn:hover {
    background: #f0f0f0;
}

/* ===== Reaction Bar ===== */
.reaction-bar {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-bar__badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #f0f4ff;
    border: 1px solid #c8d6f0;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-bar__badge:hover {
    background: #dde6f7;
}

.reaction-bar__count {
    font-weight: 600;
    color: #1264a3;
}

/* ===== Emoji Picker ===== */
.emoji-picker {
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
    position: absolute;
    top: -8px;
    right: 180px;
    z-index: 20;
}

.emoji-picker__btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

.emoji-picker__btn:hover {
